    {
        ResourceGen,    // 资源产出建筑
        Portal,         // 传送门（进入小游戏）
        Storage,        // 仓库（提升资源上限）
        Decoration,     // 装饰建筑
        Special         // 特殊建筑
    }

    /// <summary>
    /// 建筑等级配置。
    /// </summary>
    [Serializable]
    public class BuildingLevel
    {
        public int level;
        public int upgradeCost;
        public int buildCost;
        public float productionRate;    // 每秒产出量
        public int productionCapacity;  // 产出上限
        public int storageCapacity;     // 仓库容量（仅 Storage 类型）
    }

    /// <summary>
    /// 建筑配置数据（ScriptableObject）。
    /// 在 Inspector 中编辑，定义建筑的所有属性。
    /// </summary>
    [CreateAssetMenu(fileName = "NewBuilding", menuName = "HomeBase/Building Data")]
    public class BuildingData : ScriptableObject
    {
        [Header("基础信息")]
        public string buildingId;
        public string buildingName;
        [TextArea(2, 4)]
        public string description;
        public BuildingType buildingType;
        public Sprite icon;
        public GameObject prefab;

        [Header("网格配置")]
        public Vector2Int gridSize = Vector2Int.one;  // 占据的网格大小

        [Header("等级配置")]
        public BuildingLevel[] levels;

        [Header("传送门配置（仅 Portal 类型）")]
        public string targetModuleId;    // 目标模块 ID（如 "towerdefense"）
        public string targetSceneName;   // 目标场景名

        [Header("产出资源类型（仅 ResourceGen 类型）")]
        public ResourceType producedResource = ResourceType.Gold;

        /// <summary>获取指定等级的配置，超出范围返回最高等级。</summary>
        public BuildingLevel GetLevelData(int level)
        {
            if (levels == null || levels.Length == 0)
                return new BuildingLevel { level = 1, buildCost = 100 };
            int index = Mathf.Clamp(level - 1, 0, levels.Length - 1);
            return levels[index];
        }

        /// <summary>最大等级。</summary>
        public int MaxLevel => levels != null ? levels.Length : 1;
    }
}

using System;
using System.Collections;
using System.Collections.Generic;
using UnityEngine;
using UnityEngine.SceneManagement;

namespace Sttop5.Shared.Core
{
    /// <summary>
    /// 场景加载管理器，处理 Additive 场景加载/卸载。
    /// 所有场景切换通过此类进行，支持加载进度回调。
    /// </summary>
    public class SceneLoader : Singleton<SceneLoader>
    {
        private readonly HashSet<string> _loadedScenes = new HashSet<string>();
        private bool _isLoading = false;

        public bool IsLoading => _isLoading;
        public IReadOnlyCollection<string> LoadedScenes => _loadedScenes;

        /// <summary>
        /// 以 Additive 模式加载场景。
        /// </summary>
        public void LoadSceneAdditive(string sceneName, Action onLoaded = null)
        {
            if (_isLoading)
            {
                Debug.LogWarning($"[SceneLoader] 正在加载中，忽略请求: {sceneName}");
                return;
            }

            if (_loadedScenes.Contains(sceneName))
            {
                Debug.LogWarning($"[SceneLoader] 场景已加载: {sceneName}");
                onLoaded?.Invoke();
                return;
            }

            StartCoroutine(LoadSceneAdditiveCoroutine(sceneName, onLoaded));
        }

        /// <summary>
        /// 卸载已加载的 Additive 场景。
        /// </summary>
        public void UnloadScene(string sceneName, Action onUnloaded = null)
        {
            if (!_loadedScenes.Contains(sceneName))
            {
                Debug.LogWarning($"[SceneLoader] 场景未加载，无法卸载: {sceneName}");
                onUnloaded?.Invoke();
                return;
            }

            StartCoroutine(UnloadSceneCoroutine(sceneName, onUnloaded));
        }

        /// <summary>
        /// 卸载所有通过 SceneLoader 加载的场景（保留根场景）。
        /// </summary>
        public void UnloadAllScenes(Action onAllUnloaded = null)
        {
            if (_loadedScenes.Count == 0)
            {
                onAllUnloaded?.Invoke();
                return;
            }

            StartCoroutine(UnloadAllScenesCoroutine(onAllUnloaded));
        }

        /// <summary>
        /// 检查指定场景是否已加载。
        /// </summary>
        public bool IsSceneLoaded(string sceneName)
        {
            return _loadedScenes.Contains(sceneName);
        }

        private IEnumerator LoadSceneAdditiveCoroutine(string sceneName, Action onLoaded)
        {
            _isLoading = true;

            var op = SceneManager.LoadSceneAsync(sceneName, LoadSceneMode.Additive);
            if (op == null)
            {
                Debug.LogError($"[SceneLoader] 无法加载场景: {sceneName}");
                _isLoading = false;
                yield break;
            }

            while (!op.isDone)
            {
                yield return null;
            }

            _loadedScenes.Add(sceneName);

            Scene loadedScene = SceneManager.GetSceneByName(sceneName);
            if (loadedScene.IsValid())
            {
                SceneManager.SetActiveScene(loadedScene);
            }

            _isLoading = false;
            Debug.Log($"[SceneLoader] 场景已加载: {sceneName}");
            onLoaded?.Invoke();
        }

        private IEnumerator UnloadSceneCoroutine(string sceneName, Action onUnloaded)
        {
            _isLoading = true;

            var op = SceneManager.UnloadSceneAsync(sceneName);
            if (op == null)
            {
                Debug.LogError($"[SceneLoader] 无法卸载场景: {sceneName}");
                _isLoading = false;
                yield break;
            }

            while (!op.isDone)
            {
                yield return null;
            }

            _loadedScenes.Remove(sceneName);
            _isLoading = false;
            Debug.Log($"[SceneLoader] 场景已卸载: {sceneName}");
            onUnloaded?.Invoke();
        }

        private IEnumerator UnloadAllScenesCoroutine(Action onAllUnloaded)
        {
            var scenesToUnload = new List<string>(_loadedScenes);
            foreach (var sceneName in scenesToUnload)
            {
                yield return UnloadSceneCoroutine(sceneName, null);
            }
            onAllUnloaded?.Invoke();
        }
    }
}

using System;
using System.Collections.Generic;
using UnityEngine;
using Sttop5.Shared.Core;
using Sttop5.Shared.Player;

namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 资源建筑，自动产出资源。
    /// </summary>
    public class ResourceBuilding : BuildingBase
    {
        private float _accumulated;

        protected override void BuildingUpdate()
        {
            if (_data == null || _data.buildingType != BuildingType.ResourceGen)
                return;

            var levelData = CurrentLevelData;
            if (levelData.productionRate <= 0) return;

            _productionTimer += Time.deltaTime;
            float interval = 1f / levelData.productionRate;

            if (_productionTimer >= interval)
            {
                _productionTimer -= interval;
                _accumulated++;

                if (_accumulated >= levelData.productionCapacity)
                {
                    CollectResources();
                }
            }
        }

        /// <summary>
        /// 收集已产出的资源。
        /// </summary>
        public int CollectResources()
        {
            int collected = (int)_accumulated;
            if (collected <= 0) return 0;

            _accumulated = 0;

            var profile = PlayerProfile.Instance;
            if (profile != null)
            {
                switch (_data.producedResource)
                {
                    case ResourceType.Gold:
                        profile.AddGold(collected, "home_resource");
                        break;
                    case ResourceType.Diamond:
                        profile.AddDiamond(collected, "home_resource");
                        break;
                }
            }

            Debug.Log($"[ResourceBuilding] 收集 {collected} {_data.producedResource} from {_data.buildingName}");
            return collected;
        }

        /// <summary>
        /// 计算离线收益。
        /// </summary>
        public int CalculateOfflineEarnings(float offlineSeconds)
        {
            if (_data == null || _data.buildingType != BuildingType.ResourceGen) return 0;
            var levelData = CurrentLevelData;
            return Mathf.FloorToInt(levelData.productionRate * offlineSeconds);
        }

        protected override void OnUpgraded()
        {
            // 升级后立即收集一次
            CollectResources();
        }
    }
}

using UnityEngine;
using UnityEngine.UI;
using System.Collections;
using TowerDefense.Data;
using TowerDefense.Core;

namespace TowerDefense.UI
{
    public class ShopItemUI : MonoBehaviour
    {
        [Header("UI References")]
        [SerializeField] private Image _iconImage;
        [SerializeField] private Image _cardBackground;  // 卡片背景
        [SerializeField] private Text _nameText;
        [SerializeField] private Text _descText;
        [SerializeField] private Text _priceText;
        [SerializeField] private Text _originalPriceText;  // 原价（划线价）
        [SerializeField] private Text _tagText;
        [SerializeField] private Text _discountText;
        [SerializeField] private Button _buyButton;
        [SerializeField] private GameObject _tagObject;
        [SerializeField] private GameObject _discountObject;
        [SerializeField] private GameObject _soldOutObject;
        [SerializeField] private GameObject _originalPriceObject;  // 原价区域
        [SerializeField] private CanvasGroup _canvasGroup;  // 用于动画

        // 卡片颜色方案 - 按分类
        private static readonly Color ResourceCardColor = new Color(0.25f, 0.22f, 0.15f, 0.95f);
        private static readonly Color HeroCardColor = new Color(0.15f, 0.18f, 0.28f, 0.95f);
        private static readonly Color TowerCardColor = new Color(0.15f, 0.25f, 0.18f, 0.95f);
        private static readonly Color SpecialCardColor = new Color(0.28f, 0.15f, 0.22f, 0.95f);

        // 标签颜色
        private static readonly Color TagNewColor = new Color(0.2f, 0.8f, 1f, 1f);
        private static readonly Color TagHotColor = new Color(1f, 0.4f, 0.2f, 1f);
        private static readonly Color TagDailyColor = new Color(0.3f, 0.9f, 0.4f, 1f);
        private static readonly Color TagLimitColor = new Color(1f, 0.75f, 0.1f, 1f);

        private ShopItemData _itemData;
        private ShopPanel _shopPanel;

        public void Setup(ShopItemData itemData, ShopPanel shopPanel)
        {
            _itemData = itemData;
            _shopPanel = shopPanel;

            // 卡片背景色
            if (_cardBackground != null)
            {
                _cardBackground.color = itemData.category switch
                {
                    ShopCategory.Resource => ResourceCardColor,
                    ShopCategory.Hero => HeroCardColor,
                    ShopCategory.Tower => TowerCardColor,
                    ShopCategory.Special => SpecialCardColor,
                    _ => new Color(0.2f, 0.2f, 0.2f, 0.9f)
                };
            }

            if (_nameText != null)
                _nameText.text = itemData.name;

            if (_descText != null)
            {
                string rewardText = BuildRewardText(itemData);
                _descText.text = string.IsNullOrEmpty(rewardText) ? itemData.description : rewardText;
            }

            // Price - 折扣时显示划线原价
            if (_priceText != null)
            {
                if (itemData.currencyType == CurrencyType.Free)
                {
                    _priceText.text = "免费";
                    _priceText.color = Color.green;
                }
                else if (itemData.discount > 0)
                {
                    int discountedPrice = itemData.price * (100 - itemData.discount) / 100;
                    string symbol = ShopPanel.GetCurrencySymbol(itemData.currencyType);
                    _priceText.text = $"{symbol}{discountedPrice}";
                    _priceText.color = new Color(1f, 0.85f, 0.2f); // 金色高亮折扣价

                    // 显示原价
                    if (_originalPriceText != null)
                        _originalPriceText.text = $"{itemData.price}";
                    if (_originalPriceObject != null)
                        _originalPriceObject.SetActive(true);
                }
                else
                {
                    string symbol = ShopPanel.GetCurrencySymbol(itemData.currencyType);
                    _priceText.text = $"{symbol}{itemData.price}";
                    _priceText.color = Color.white;
                }
            }

            // 没有折扣时隐藏原价
            if (itemData.discount <= 0 && _originalPriceObject != null)
                _originalPriceObject.SetActive(false);

            // Tag - 带颜色
            if (_tagObject != null)
            {
                bool hasTag = !string.IsNullOrEmpty(itemData.tag);
                _tagObject.SetActive(hasTag);
                if (hasTag && _tagText != null)
                {
                    _tagText.text = itemData.tag;
                    // 标签颜色
                    var tagImage = _tagObject.GetComponent<Image>();
                    if (tagImage != null)
                    {
                        tagImage.color = itemData.tag.ToLower() switch
                        {
                            "new" => TagNewColor,
                            "hot" => TagHotColor,
                            "daily" => TagDailyColor,
                            "限时" => TagLimitColor,
                            _ => TagNewColor
                        };
                    }
                }
            }

            // Discount badge
            if (_discountObject != null)
            {
                bool hasDiscount = itemData.discount > 0;
                _discountObject.SetActive(hasDiscount);
                if (hasDiscount && _discountText != null)
                    _discountText.text = $"-{itemData.discount}%";
            }

            // Icon
            if (_iconImage != null)
            {
                if (!string.IsNullOrEmpty(itemData.iconPath))
                {
                    var sprite = Resources.Load<Sprite>(itemData.iconPath);
                    if (sprite != null)
                    {
                        _iconImage.sprite = sprite;
                        _iconImage.color = Color.white;
                    }
                    else
                    {
                        SetCategoryFallbackColor(itemData.category);
                    }
                }
                else
                {
                    SetCategoryFallbackColor(itemData.category);
                }
            }

            // Sold out check - 更醒目
            bool isSoldOut = itemData.isLimited && itemData.purchasedCount >= itemData.limitCount;
            if (_soldOutObject != null)
                _soldOutObject.SetActive(isSoldOut);

            if (_buyButton != null)
            {
                _buyButton.interactable = !isSoldOut;

                // 售罄时按钮变灰
                var buyImage = _buyButton.GetComponent<Image>();
                if (buyImage != null)
                {
                    buyImage.color = isSoldOut
                        ? new Color(0.3f, 0.3f, 0.3f, 1f)
                        : new Color(0.2f, 0.75f, 0.3f, 1f);  // 绿色可购买
                }

                _buyButton.onClick.RemoveAllListeners();
                _buyButton.onClick.AddListener(OnBuyClicked);
            }

            // 限购信息 - 在描述后追加
            if (_descText != null && itemData.isLimited && itemData.limitCount > 0)
            {
                int remaining = itemData.limitCount - itemData.purchasedCount;
                _descText.text += $"\n<color=#FFD700>限购{itemData.limitCount}次 (剩余{remaining}次)</color>";
            }
        }

        private void SetCategoryFallbackColor(ShopCategory category)
        {
            _iconImage.sprite = null;
            _iconImage.color = category switch
            {
                ShopCategory.Resource => new Color(1f, 0.85f, 0.2f, 1f),
                ShopCategory.Hero => new Color(0.3f, 0.7f, 1f, 1f),
                ShopCategory.Tower => new Color(0.4f, 1f, 0.4f, 1f),
                ShopCategory.Special => new Color(1f, 0.4f, 0.8f, 1f),
                _ => Color.white
            };
        }

        public static string BuildRewardText(ShopItemData data)
        {
            var parts = new System.Collections.Generic.List<string>();
            if (data.rewardGold > 0) parts.Add($"🪙×{data.rewardGold}");
            if (data.rewardDiamond > 0) parts.Add($"💎×{data.rewardDiamond}");
            if (data.rewardStamina > 0) parts.Add($"⚡×{data.rewardStamina}");
            return string.Join("  ", parts);
        }

        private void OnBuyClicked()
        {
            if (_shopPanel != null && _itemData != null)
            {
                _shopPanel.OnBuyClicked(_itemData);
            }
        }
    }
}

using System;
using System.Collections.Generic;
using UnityEngine;
using Sttop5.Shared.Core;
