using UnityEngine;
using TowerDefense.Core;

namespace TowerDefense.Data
{
    public class PlayerWallet : Singleton<PlayerWallet>
    {
        [Header("Initial Values")]
        [SerializeField] private int _initialGold = 1000;
        [SerializeField] private int _initialDiamond = 100;
        [SerializeField] private int _initialStamina = 60;

        private int _gold;
        private int _diamond;
        private int _stamina;

        /// <summary>是否代理到共享 PlayerProfile</summary>
        private bool _isProxyMode;

        public int Gold => _isProxyMode ? GetProxyGold() : _gold;
        public int Diamond => _isProxyMode ? GetProxyDiamond() : _diamond;
        public int Stamina => _isProxyMode ? GetProxyStamina() : _stamina;

        public event System.Action<int> OnGoldChanged;
        public event System.Action<int> OnDiamondChanged;
        public event System.Action<int> OnStaminaChanged;

        private Sttop5.Shared.Player.PlayerProfile _profile;

        protected override void Awake()
        {
            base.Awake();

            // 检测是否在模块模式下运行（通过场景名判断）
            string sceneName = UnityEngine.SceneManagement.SceneManager.GetActiveScene().name;
            if (sceneName == "TDGameScene" || ModuleModeDetector.IsModuleMode)
            {
                EnableProxyMode();
            }
            else
            {
                _gold = _initialGold;
                _diamond = _initialDiamond;
                _stamina = _initialStamina;
            }
        }

        /// <summary>
        /// 启用代理模式，将金币/钻石/体力操作转发到共享 PlayerProfile。
        /// </summary>
        public void EnableProxyMode()
        {
            _profile = Sttop5.Shared.Player.PlayerProfile.Instance;
            if (_profile != null)
            {
                _isProxyMode = true;
                // 同步初始值
                _gold = _profile.Gold;
                _diamond = _profile.Diamond;
                _stamina = _profile.Stamina;

                // 订阅 Profile 的变化，转发到本地事件
                _profile.OnGoldChanged += OnProxyGoldChanged;
                _profile.OnDiamondChanged += OnProxyDiamondChanged;
                _profile.OnStaminaChanged += OnProxyStaminaChanged;

                Debug.Log("[PlayerWallet] 代理模式已启用，转发到 PlayerProfile");
            }
            else
            {
                _gold = _initialGold;
                _diamond = _initialDiamond;
                _stamina = _initialStamina;
                Debug.LogWarning("[PlayerWallet] PlayerProfile 不可用，使用独立模式");
            }
        }

        /// <summary>
        /// 禁用代理模式，断开与 PlayerProfile 的连接。
        /// </summary>
        public void DisableProxyMode()
        {
            if (_profile != null)
            {
                _profile.OnGoldChanged -= OnProxyGoldChanged;
                _profile.OnDiamondChanged -= OnProxyDiamondChanged;
                _profile.OnStaminaChanged -= OnProxyStaminaChanged;
            }
            _isProxyMode = false;
            _profile = null;
        }

        #region Proxy Helpers

        private int GetProxyGold() => _profile != null ? _profile.Gold : _gold;
        private int GetProxyDiamond() => _profile != null ? _profile.Diamond : _diamond;
        private int GetProxyStamina() => _profile != null ? _profile.Stamina : _stamina;

        private void OnProxyGoldChanged(int gold)
        {
            _gold = gold;
            OnGoldChanged?.Invoke(gold);
            EventBus.Publish(new GoldChangedEvent { CurrentGold = gold, Change = 0 });
        }

        private void OnProxyDiamondChanged(int diamond)
        {
            _diamond = diamond;
            OnDiamondChanged?.Invoke(diamond);
        }

        private void OnProxyStaminaChanged(int stamina)
        {
            _stamina = stamina;
            OnStaminaChanged?.Invoke(stamina);
        }

        #endregion

        public bool HasEnoughGold(int amount) => Gold >= amount;
        public bool HasEnoughDiamond(int amount) => Diamond >= amount;

        public void AddGold(int amount)
        {
            if (amount <= 0) return;

            if (_isProxyMode && _profile != null)
            {
                _profile.AddGold(amount, "towerdefense");
                return;
            }

            _gold += amount;
            OnGoldChanged?.Invoke(_gold);
            EventBus.Publish(new GoldChangedEvent { CurrentGold = _gold, Change = amount });
        }

        public bool SpendGold(int amount)
        {
            if (!HasEnoughGold(amount)) return false;

            if (_isProxyMode && _profile != null)
            {
                bool result = _profile.SpendGold(amount, "towerdefense");
                if (result)
                {
                    _gold = _profile.Gold;
                }
                return result;
            }

            _gold -= amount;
            OnGoldChanged?.Invoke(_gold);
            EventBus.Publish(new GoldChangedEvent { CurrentGold = _gold, Change = -amount });
            return true;
        }

        public void AddDiamond(int amount)
        {
            if (amount <= 0) return;

            if (_isProxyMode && _profile != null)
            {
                _profile.AddDiamond(amount, "towerdefense");
                return;
            }

            _diamond += amount;
            OnDiamondChanged?.Invoke(_diamond);
        }

        public bool SpendDiamond(int amount)
        {
            if (!HasEnoughDiamond(amount)) return false;

            if (_isProxyMode && _profile != null)
            {
                return _profile.SpendDiamond(amount, "towerdefense");
            }

            _diamond -= amount;
            OnDiamondChanged?.Invoke(_diamond);
            return true;
        }

        public void AddStamina(int amount)
        {
            if (amount <= 0) return;

            if (_isProxyMode && _profile != null)
            {
                _profile.AddStamina(amount);
                return;
            }

            _stamina += amount;
            OnStaminaChanged?.Invoke(_stamina);
        }

        public bool SpendStamina(int amount)
        {
            if (Stamina < amount) return false;

            if (_isProxyMode && _profile != null)
            {
                return _profile.SpendStamina(amount);
            }

            _stamina -= amount;
            OnStaminaChanged?.Invoke(_stamina);
            return true;
        }

        private new void OnDestroy()
        {
            DisableProxyMode();
        }
    }
}

using System;
using UnityEngine;
using Sttop5.Shared.Core;
using Sttop5.Shared.Save;

namespace Sttop5.Shared.Player
{
    /// <summary>
    /// 统一玩家档案，管理跨所有模块共享的玩家数据。
    /// 包含货币（金币、钻石）、等级、经验值。
    /// </summary>
    public class PlayerProfile : Singleton<PlayerProfile>
    {
        [Header("初始值")]
        [SerializeField] private int _initialGold = 1000;
        [SerializeField] private int _initialDiamond = 100;
        [SerializeField] private int _initialStamina = 60;

        [Header("等级配置")]
        [SerializeField] private int _maxLevel = 99;
        [SerializeField] private int _baseExp = 100;
        [SerializeField] private int _expIncrement = 50;

        private int _gold;
        private int _diamond;
        private int _stamina;
        private int _level = 1;
        private int _currentExp;

        #region 属性

        public int Gold => _gold;
        public int Diamond => _diamond;
        public int Stamina => _stamina;
        public int Level => _level;
        public int CurrentExp => _currentExp;
        public int MaxLevel => _maxLevel;
        public int ExpToNextLevel => GetExpRequiredForLevel(_level);
        public float ExpProgress => _level >= _maxLevel ? 1f : (float)_currentExp / ExpToNextLevel;
        public bool IsMaxLevel => _level >= _maxLevel;

        #endregion

        #region 事件

        public event Action<int> OnGoldChanged;
        public event Action<int> OnDiamondChanged;
        public event Action<int> OnStaminaChanged;
        public event Action<int> OnLevelChanged;
        public event Action<int, int> OnExpChanged;

        #endregion

        protected override void Awake()
        {
            base.Awake();
            _gold = _initialGold;
            _diamond = _initialDiamond;
            _stamina = _initialStamina;
        }

        private void Start()
        {
            LoadFromSave();
        }

        #region 金币

        public bool HasEnoughGold(int amount) => _gold >= amount;

        public void AddGold(int amount, string source = "")
        {
            if (amount <= 0) return;
            _gold += amount;
            OnGoldChanged?.Invoke(_gold);
            GlobalEventBus.Publish(new PlayerCurrencyChangedEvent
            {
                Source = source,
                GoldDelta = amount,
                DiamondDelta = 0
            });
        }

        public bool SpendGold(int amount, string source = "")
        {
            if (!HasEnoughGold(amount)) return false;
            _gold -= amount;
            OnGoldChanged?.Invoke(_gold);
            GlobalEventBus.Publish(new PlayerCurrencyChangedEvent
            {
                Source = source,
                GoldDelta = -amount,
                DiamondDelta = 0
            });
            return true;
        }

        #endregion

        #region 钻石

        public bool HasEnoughDiamond(int amount) => _diamond >= amount;

        public void AddDiamond(int amount, string source = "")
        {
            if (amount <= 0) return;
            _diamond += amount;
            OnDiamondChanged?.Invoke(_diamond);
            GlobalEventBus.Publish(new PlayerCurrencyChangedEvent
            {
                Source = source,
                GoldDelta = 0,
                DiamondDelta = amount
            });
        }

        public bool SpendDiamond(int amount, string source = "")
        {
            if (!HasEnoughDiamond(amount)) return false;
            _diamond -= amount;
            OnDiamondChanged?.Invoke(_diamond);
            GlobalEventBus.Publish(new PlayerCurrencyChangedEvent
            {
                Source = source,
                GoldDelta = 0,
                DiamondDelta = -amount
            });
            return true;
        }

        #endregion

        #region 体力

        public bool HasEnoughStamina(int amount) => _stamina >= amount;

        public void AddStamina(int amount)
        {
            if (amount <= 0) return;
            _stamina += amount;
            OnStaminaChanged?.Invoke(_stamina);
        }

        public bool SpendStamina(int amount)
        {
            if (!HasEnoughStamina(amount)) return false;
            _stamina -= amount;
            OnStaminaChanged?.Invoke(_stamina);
            return true;
        }

        #endregion

        #region 等级与经验

        public int GetExpRequiredForLevel(int level)
        {
            if (level >= _maxLevel) return int.MaxValue;
            return _baseExp + (level - 1) * _expIncrement;
        }

        public void AddExp(int amount)
        {
            if (amount <= 0 || IsMaxLevel) return;

            int oldLevel = _level;
            _currentExp += amount;

            while (_currentExp >= ExpToNextLevel && !IsMaxLevel)
            {
                _currentExp -= ExpToNextLevel;
                _level++;
            }

            if (IsMaxLevel)
                _currentExp = 0;

            OnExpChanged?.Invoke(_currentExp, ExpToNextLevel);
            GlobalEventBus.Publish(new PlayerLevelChangedEvent
            {
                OldLevel = oldLevel,
                NewLevel = _level,
                CurrentExp = _currentExp,
                ExpToNext = ExpToNextLevel
            });

            if (_level != oldLevel)
            {
                OnLevelChanged?.Invoke(_level);
                Debug.Log($"[PlayerProfile] 升级! Lv.{oldLevel} → Lv.{_level}");
            }
        }

        #endregion

        #region 存档

        public void LoadFromSave()
        {
            var saveSystem = SaveSystem.Instance;
            if (saveSystem == null || saveSystem.CurrentSave == null) return;

            var data = saveSystem.CurrentSave.player;
            _gold = data.gold > 0 ? data.gold : _initialGold;
            _diamond = data.diamond > 0 ? data.diamond : _initialDiamond;
            _stamina = data.stamina > 0 ? data.stamina : _initialStamina;
            _level = Mathf.Clamp(data.playerLevel, 1, _maxLevel);
            _currentExp = Mathf.Clamp(data.playerExp, 0, ExpToNextLevel);

            Debug.Log($"[PlayerProfile] 从存档加载: Lv.{_level}, Gold={_gold}, Diamond={_diamond}");
        }

        public void PersistToSave()
        {
            var saveSystem = SaveSystem.Instance;
            if (saveSystem == null || saveSystem.CurrentSave == null) return;

            saveSystem.CurrentSave.player.gold = _gold;
            saveSystem.CurrentSave.player.diamond = _diamond;
            saveSystem.CurrentSave.player.stamina = _stamina;
            saveSystem.CurrentSave.player.playerLevel = _level;
            saveSystem.CurrentSave.player.playerExp = _currentExp;
            saveSystem.SaveGame();
        }

        #endregion

        private void OnApplicationPause(bool pauseStatus)
        {
            if (pauseStatus) PersistToSave();
        }

        private void OnApplicationQuit()
        {
            PersistToSave();
        }

        private void OnDisable()
        {
            PersistToSave();
        }
    }
}

