            {
                if (itemData.currencyType == CurrencyType.Free)
                {
                    _priceText.text = "免费";
                    _priceText.color = Color.green;
                }
                else if (itemData.discount > 0)
                {
                    int discountedPrice = itemData.price * (100 - itemData.discount) / 100;
                    string symbol = ShopPanel.GetCurrencySymbol(itemData.currencyType);
                    _priceText.text = $"{symbol}{discountedPrice}";
                    _priceText.color = new Color(1f, 0.85f, 0.2f); // 金色高亮折扣价

                    // 显示原价
                    if (_originalPriceText != null)
                        _originalPriceText.text = $"{itemData.price}";
                    if (_originalPriceObject != null)
                        _originalPriceObject.SetActive(true);
                }
                else
                {
                    string symbol = ShopPanel.GetCurrencySymbol(itemData.currencyType);
                    _priceText.text = $"{symbol}{itemData.price}";
                    _priceText.color = Color.white;
                }
            }

            // 没有折扣时隐藏原价
            if (itemData.discount <= 0 && _originalPriceObject != null)
                _originalPriceObject.SetActive(false);

            // Tag - 带颜色
            if (_tagObject != null)
            {
                bool hasTag = !string.IsNullOrEmpty(itemData.tag);
                _tagObject.SetActive(hasTag);
                if (hasTag && _tagText != null)
                {
                    _tagText.text = itemData.tag;
                    // 标签颜色
                    var tagImage = _tagObject.GetComponent<Image>();
                    if (tagImage != null)
                    {
                        tagImage.color = itemData.tag.ToLower() switch
                        {
                            "new" => TagNewColor,
                            "hot" => TagHotColor,
                            "daily" => TagDailyColor,
                            "限时" => TagLimitColor,
                            _ => TagNewColor
                        };
                    }
                }
            }

            // Discount badge
            if (_discountObject != null)
            {
                bool hasDiscount = itemData.discount > 0;
                _discountObject.SetActive(hasDiscount);
                if (hasDiscount && _discountText != null)
                    _discountText.text = $"-{itemData.discount}%";
            }

            // Icon
            if (_iconImage != null)
            {
                if (!string.IsNullOrEmpty(itemData.iconPath))
                {
                    var sprite = Resources.Load<Sprite>(itemData.iconPath);
                    if (sprite != null)
                    {
                        _iconImage.sprite = sprite;
                        _iconImage.color = Color.white;
                    }
                    else
                    {
                        SetCategoryFallbackColor(itemData.category);
                    }
                }
                else
                {
                    SetCategoryFallbackColor(itemData.category);
                }
            }

            // Sold out check - 更醒目
            bool isSoldOut = itemData.isLimited && itemData.purchasedCount >= itemData.limitCount;
            if (_soldOutObject != null)
                _soldOutObject.SetActive(isSoldOut);

            if (_buyButton != null)
            {
                _buyButton.interactable = !isSoldOut;

                // 售罄时按钮变灰
                var buyImage = _buyButton.GetComponent<Image>();
                if (buyImage != null)
                {
                    buyImage.color = isSoldOut
                        ? new Color(0.3f, 0.3f, 0.3f, 1f)
                        : new Color(0.2f, 0.75f, 0.3f, 1f);  // 绿色可购买
                }

                _buyButton.onClick.RemoveAllListeners();
                _buyButton.onClick.AddListener(OnBuyClicked);
            }

            // 限购信息 - 在描述后追加
            if (_descText != null && itemData.isLimited && itemData.limitCount > 0)
            {
                int remaining = itemData.limitCount - itemData.purchasedCount;
                _descText.text += $"\n<color=#FFD700>限购{itemData.limitCount}次 (剩余{remaining}次)</color>";
            }
        }

        private void SetCategoryFallbackColor(ShopCategory category)
        {
            _iconImage.sprite = null;
            _iconImage.color = category switch
            {
                ShopCategory.Resource => new Color(1f, 0.85f, 0.2f, 1f),
                ShopCategory.Hero => new Color(0.3f, 0.7f, 1f, 1f),
                ShopCategory.Tower => new Color(0.4f, 1f, 0.4f, 1f),
                ShopCategory.Special => new Color(1f, 0.4f, 0.8f, 1f),
                _ => Color.white
            };
        }

        public static string BuildRewardText(ShopItemData data)
        {
            var parts = new System.Collections.Generic.List<string>();
            if (data.rewardGold > 0) parts.Add($"🪙×{data.rewardGold}");
            if (data.rewardDiamond > 0) parts.Add($"💎×{data.rewardDiamond}");
            if (data.rewardStamina > 0) parts.Add($"⚡×{data.rewardStamina}");
            return string.Join("  ", parts);
        }

        private void OnBuyClicked()
        {
            if (_shopPanel != null && _itemData != null)
            {
                _shopPanel.OnBuyClicked(_itemData);
            }
        }
    }
}

using System;
using System.Collections.Generic;
using UnityEngine;
using Sttop5.Shared.Core;
using Sttop5.Shared.Player;

namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 建筑存档数据。
    /// </summary>
    [Serializable]
    public class BuildingSaveEntry
    {
        public string buildingId;
        public float posX;
        public float posY;
        public int level;
    }

    /// <summary>
    /// 家园存档数据。
    /// </summary>
    [Serializable]
    public class HomeSaveData
    {
        public int wood;
        public int stone;
        public int food;
        public List<BuildingSaveEntry> buildings = new List<BuildingSaveEntry>();
    }

    /// <summary>
    /// 建筑管理器，负责建筑的放置、升级和拆除。
    /// </summary>
    public class BuildingManager : MonoBehaviour
    {
        [Header("建筑配置列表")]
        [SerializeField] private BuildingData[] _availableBuildings;

        private List<BuildingBase> _buildings = new List<BuildingBase>();

        public BuildingData[] AvailableBuildings => _availableBuildings;
        public IReadOnlyList<BuildingBase> Buildings => _buildings;

        #region 放置与检测

        /// <summary>
        /// 在指定世界坐标放置建筑。
        /// </summary>
        public BuildingBase PlaceBuilding(BuildingData data, Vector3 worldPos)
        {
            // 扣除建造费用
            var levelData = data.GetLevelData(1);
            var profile = PlayerProfile.Instance;
            if (profile != null && levelData.buildCost > 0 && !profile.HasEnoughGold(levelData.buildCost))
            {
                Debug.LogWarning("[BuildingManager] 金币不足");
                return null;
            }
            profile?.SpendGold(levelData.buildCost, "building_place");

            // 实例化建筑
            GameObject go = data.prefab != null
                ? Instantiate(data.prefab, worldPos, Quaternion.identity, transform)
                : CreatePlaceholderBuilding(data, worldPos);

            BuildingBase building = go.GetComponent<BuildingBase>();
            if (building == null)
                building = go.AddComponent<BuildingBase>();

            building.Initialize(data);
            _buildings.Add(building);
            Debug.Log($"[BuildingManager] 建筑已放置: {data.buildingName} at {worldPos}");
            return building;
        }

        /// <summary>
        /// 拆除指定建筑。
        /// </summary>
        public bool RemoveBuilding(BuildingBase building)
        {
            if (building == null || !_buildings.Contains(building))
                return false;

            _buildings.Remove(building);
            building.Demolish();
            return true;
        }

        /// <summary>
        /// 获取指定位置附近的建筑。
        /// </summary>
        public BuildingBase GetBuildingNear(Vector3 worldPos, float radius = 1f)
        {
            float minDist = float.MaxValue;
            BuildingBase nearest = null;
            foreach (var b in _buildings)
            {
                if (b == null) continue;
                float dist = Vector3.Distance(b.transform.position, worldPos);
                if (dist < radius && dist < minDist)
                {
                    minDist = dist;
                    nearest = b;
                }
            }
            return nearest;
        }

        #endregion

        #region 存档

        /// <summary>
        /// 导出所有建筑的存档数据。
        /// </summary>
        public List<BuildingSaveEntry> ExportSaveData()
        {
            var result = new List<BuildingSaveEntry>();
            foreach (var building in _buildings)
            {
                if (building == null) continue;
                result.Add(new BuildingSaveEntry
                {
                    buildingId = building.Data.buildingId,
                    posX = building.transform.position.x,
                    posY = building.transform.position.y,
                    level = building.CurrentLevel
                });
            }
            return result;
        }

        /// <summary>
        /// 从存档数据恢复所有建筑。
        /// </summary>
        public void RestoreFromSaveData(List<BuildingSaveEntry> entries)
        {
            if (entries == null) return;

            foreach (var entry in entries)
            {
                BuildingData data = FindBuildingData(entry.buildingId);
                if (data == null)
                {
                    Debug.LogWarning($"[BuildingManager] 未找到建筑配置: {entry.buildingId}");
                    continue;
                }

                Vector3 worldPos = new Vector3(entry.posX, entry.posY, 0f);
                GameObject go = data.prefab != null
                    ? Instantiate(data.prefab, worldPos, Quaternion.identity, transform)
                    : CreatePlaceholderBuilding(data, worldPos);

                BuildingBase building = go.GetComponent<BuildingBase>();
                if (building == null)
                    building = go.AddComponent<BuildingBase>();

                building.RestoreFromSave(data, entry.level);
                _buildings.Add(building);
            }

            Debug.Log($"[BuildingManager] 从存档恢复 {entries.Count} 个建筑");
        }

        #endregion

        #region 辅助

        private BuildingData FindBuildingData(string buildingId)
        {
            if (_availableBuildings == null) return null;
            foreach (var data in _availableBuildings)
            {
                if (data.buildingId == buildingId)
                    return data;
            }
            return null;
        }

        private GameObject CreatePlaceholderBuilding(BuildingData data, Vector3 worldPos)
        {
            GameObject go = new GameObject($"Building_{data.buildingName}");
            go.transform.position = worldPos;
            go.transform.SetParent(transform);

            SpriteRenderer sr = go.AddComponent<SpriteRenderer>();
            sr.sprite = data.icon;
            if (sr.sprite == null)
            {
                sr.color = GetBuildingColor(data.buildingType);
            }
            sr.sortingOrder = 10;

            return go;
        }

        private Color GetBuildingColor(BuildingType type)
        {
            switch (type)
            {
                case BuildingType.ResourceGen: return new Color(0.2f, 0.8f, 0.3f);
                case BuildingType.Portal: return new Color(0.3f, 0.5f, 1f);
                case BuildingType.Storage: return new Color(0.9f, 0.7f, 0.2f);
                case BuildingType.Decoration: return new Color(0.9f, 0.4f, 0.7f);
                case BuildingType.Special: return new Color(1f, 0.5f, 0.1f);
                default: return Color.white;
            }
        }

        #endregion
    }
}

